import React,{useState,useEffect} from "react";
import "./App.css";

import {Bar, Doughnut } from "react-chartjs-2";
import SubscriptionForm from "./SubscriptionForm";
import Dashboard from "./Dashboard";
import SpendingChart from "./SpendingChart";


import {
Chart as ChartJS,
CategoryScale,
LinearScale,
BarElement,
ArcElement,
Title,
Tooltip,
Legend
} from "chart.js";

ChartJS.register(
CategoryScale,
LinearScale,
BarElement,
ArcElement,
Title,
Tooltip,
Legend
);

function App(){

const [transactions,setTransactions] = useState([]);
const [amount,setAmount] = useState("");
const todaySavings=transactions.reduce((total,t)=>total + t.saved, 0).toFixed(2);
const [subscriptions, setSubscriptions] = useState([]);

useEffect(()=>{
fetchTransactions();
},[]);

const fetchTransactions = async () =>{

const res = await fetch("http://localhost:5000/transactions");
const data = await res.json();

setTransactions(data);

}

const addTransaction = async () =>{

const res = await fetch("http://localhost:5000/transaction",{

method:"POST",
headers:{
"Content-Type":"application/json"
},
body:JSON.stringify({amount})

});

alert("Transaction Added Successfully!");

await res.json();

setAmount("");

fetchTransactions();

}

const clearTransactions =async () => {
    await fetch("http://localhost:5000/clear",{
        method:"DELETE" 
    });
fetchTransactions();
}

const totalSavings =
transactions.reduce((sum,t)=>sum + t.saved,0);

const chartData = {
labels: transactions.map((t,i)=>"T"+(i+1)),
datasets:[
{
label:"Savings",
data: transactions.map(t=>t.saved),
backgroundColor: "#22c55e"
}
]
};

const goal = 1000;

const goalData = {
  labels: ["Saved", "Remaining"],
  datasets: [
    {
      data: [totalSavings, Math.max(goal - totalSavings, 0)],
      backgroundColor: ["#22c55e", "#e5e7eb"],
    },
  ],
};

const progress =(totalSavings/goal)*100;

const getAdvice = () => {
  if (totalSavings < 100) {
    return "Try saving small amounts daily to build your habit.";
  } 
  else if (totalSavings < 500) {
    return "Great start! Consider setting a weekly savings goal.";
  } 
  else {
    return "Excellent! You are building strong financial discipline.";
  }
};

return (
<div className="app">

  {/* Sidebar */}
  <div className="sidebar">
    <h2>Smart Savings</h2>

    <ul>
      <li>Dashboard</li>
      <li>Transactions</li>
      <li>Analytics</li>
    </ul>
  </div>

  <div className="navbar">
    <h2>Smart Savings Dashboard</h2>
    <div className="user">
        <span>Welcome, User</span>
    </div>
  </div>

    <div>
      <Dashboard />
    </div>

  {/* Main Content */}
  <div className="main">

    <h1>Dashboard</h1>

    {/* Top Cards */}
    <div className="cards">

      <div className="card">
        <h3>Total Savings</h3>
        <h1>₹{totalSavings.toFixed(2)}</h1>
      </div>

      <div className="card">
        <h3>Total Transactions</h3>
        <h1>{transactions.length}</h1>
      </div>

      <div className="card">
        <h3>Today's Savings</h3>
        <h1>₹{todaySavings}</h1>
      </div>

      <div className="card">
        <h3>AI Savings Advisor</h3>
        <p>{getAdvice()}</p>
      </div>

    </div>

    <div className="progress-bar">
      <div
        className="progress-fill"
        style={{ width: progress + "%" }}
      ></div>
    </div>

    <p>{progress.toFixed(0)}% completed</p>

    {/* Chart */}
    <div className="card chart">
      <h3>Savings Overview</h3>
      <Bar data={chartData} />
    </div>

    <div className="card">
      <h3>Goal Tracker</h3>
      <Doughnut data={goalData}/>
    </div>

      <div>
      <h1>Subscription Manager</h1>
      <SubscriptionForm />
    </div>



    {/* Add Transaction */}
    <div className="card">

      <h3>Add Transaction</h3>

      <input
        type="number"
        placeholder="Enter transaction"
        value={amount}
        onChange={(e)=>setAmount(e.target.value)}
      />

      <button onClick={addTransaction}>
        Add
      </button>

      <button onClick={clearTransactions}>
        Clear
      </button>

    </div>

    {/* History */}
  <div className="card history">

<h3>Transaction History</h3>

<table>

<thead>
<tr>
<th>Amount</th>
<th>Saved</th>
</tr>
</thead>

<tbody>
{transactions.map((t,i)=>(
<tr key={i}>
<td>₹{t.amount}</td>
<td>₹{t.saved}</td>
</tr>
))}
</tbody>

</table>
<SpendingChart subscriptions={subscriptions} />

</div>

  </div>

</div>
)

}

export default App;
